from lxml import etree

def process_soap_request(soap_request):
    # Define the DTD for validation
    dtd_string = '''
    <!ELEMENT soapenv:Envelope (soapenv:Header?, soapenv:Body)>
    <!ELEMENT soapenv:Header (#PCDATA)>
    <!ELEMENT soapenv:Body (#PCDATA)>
    '''
    dtd = etree.DTD(etree.XML(dtd_string))

    # Parse the SOAP request
    try:
        root = etree.fromstring(soap_request)
    except etree.XMLSyntaxError as e:
        return f"XML Syntax Error: {str(e)}"

    # Validate against the DTD
    if not dtd.validate(root):
        return f"DTD Validation Error: {dtd.error_log.last_error}"

    # Extract the SOAP Body
    body = root.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
    if body is not None:
        return etree.tostring(body, pretty_print=True).decode()
    else:
        return "No SOAP Body found."